using Payments;

namespace Payments.Tests;

[TestClass]
public class PaymentGatewayChargeTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup()
    {
        _gateway = new PaymentGateway();
    }

    [TestMethod]
    public async Task ChargeAsync_ValidCard_ReturnsSuccessResult()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 49.99m);

        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(result.ChargeId));
    }

    [TestMethod]
    public async Task ChargeAsync_ReturnsUniqueChargeId()
    {
        var result1 = await _gateway.ChargeAsync("tok_visa_1", 10.00m);
        var result2 = await _gateway.ChargeAsync("tok_visa_2", 20.00m);

        Assert.AreNotEqual(result1.ChargeId, result2.ChargeId);
    }

    [TestMethod]
    public async Task ChargeAsync_ZeroAmount_ReturnsFailure()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 0m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_NegativeAmount_ReturnsFailure()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", -5.00m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_NullToken_ThrowsArgumentNullException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentNullException>(
            () => _gateway.ChargeAsync(null!, 10.00m));
    }

    [TestMethod]
    public async Task ChargeAsync_EmptyToken_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync("", 10.00m));
    }

    [TestMethod]
    public async Task ChargeAsync_WhitespaceToken_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync("   ", 10.00m));
    }

    [TestMethod]
    [DataRow(0.01)]
    [DataRow(1.00)]
    [DataRow(999.99)]
    [DataRow(10000.00)]
    public async Task ChargeAsync_VariousValidAmounts_ReturnsSuccess(double amount)
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", (decimal)amount);

        Assert.IsTrue(result.Success);
    }
}

[TestClass]
public class PaymentGatewayRefundTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup()
    {
        _gateway = new PaymentGateway();
    }

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsSuccessResult()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 25.00m);
        var refund = await _gateway.RefundAsync(charge.ChargeId);

        Assert.IsTrue(refund.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(refund.RefundId));
    }

    [TestMethod]
    public async Task RefundAsync_InvalidChargeId_ReturnsFailure()
    {
        var result = await _gateway.RefundAsync("nonexistent_charge_id");

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task RefundAsync_NullChargeId_ThrowsArgumentNullException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentNullException>(
            () => _gateway.RefundAsync(null!));
    }

    [TestMethod]
    public async Task RefundAsync_EmptyChargeId_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.RefundAsync(""));
    }

    [TestMethod]
    public async Task RefundAsync_ReturnsUniqueRefundId()
    {
        var charge1 = await _gateway.ChargeAsync("tok_visa_1", 10.00m);
        var charge2 = await _gateway.ChargeAsync("tok_visa_2", 20.00m);

        var refund1 = await _gateway.RefundAsync(charge1.ChargeId);
        var refund2 = await _gateway.RefundAsync(charge2.ChargeId);

        Assert.AreNotEqual(refund1.RefundId, refund2.RefundId);
    }

    [TestMethod]
    public async Task RefundAsync_DoubleRefund_SecondReturnsFailure()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 30.00m);

        var first = await _gateway.RefundAsync(charge.ChargeId);
        var second = await _gateway.RefundAsync(charge.ChargeId);

        Assert.IsTrue(first.Success);
        Assert.IsFalse(second.Success, "Refunding the same charge twice should fail.");
    }
}

[TestClass]
public class PaymentGatewayEdgeCaseTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup()
    {
        _gateway = new PaymentGateway();
    }

    [TestMethod]
    public async Task ChargeAsync_VeryLargeAmount_ReturnsFailure()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 1_000_000_000m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_SmallestCentAmount_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 0.01m);

        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task RefundAsync_FailedCharge_ThrowsOrReturnsFailure()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", -1m);

        // A failed charge should not be refundable
        if (charge.Success)
        {
            Assert.Fail("Negative amount should not produce a successful charge.");
        }
    }

    [TestMethod]
    public async Task ChargeAsync_ConcurrentCharges_AllReturnUniqueIds()
    {
        var tasks = Enumerable.Range(1, 10)
            .Select(i => _gateway.ChargeAsync($"tok_card_{i}", 10.00m + i))
            .ToArray();

        var results = await Task.WhenAll(tasks);

        var chargeIds = results.Where(r => r.Success).Select(r => r.ChargeId).ToList();
        Assert.AreEqual(chargeIds.Count, chargeIds.Distinct().Count(),
            "All concurrent charges must have unique IDs.");
    }

    [TestMethod]
    public void PaymentGateway_CanBeInstantiated()
    {
        var gateway = new PaymentGateway();
        Assert.IsNotNull(gateway);
    }
}

